import React from 'react';
import { useNavigate } from 'react-router-dom';

const caseList = [
  { id: 1, title: "Too Good to Be True? It Was.", image: "/images/homepage/case1.jpg" },
  { id: 2, title: "Oops… That Wasn't What I Thought!", image: "/images/homepage/case2.jpg" },
  { id: 3, title: "Not Your Average Snapchat Friend!", image: "/images/homepage/case3.jpg" },
  { id: 4, title: "Wait… Was That Even a Real Investment?", image: "/images/homepage/case4.jpg" }
];

export default function HomePage() {
  const navigate = useNavigate();

  return (
    <div className="content-card"> {/* 使用全局样式类 */}
      <div style={styles.container}>
        <h2 style={styles.sectionTitle}>
          🧑‍🏫 Learn from Real Cyber Incidents
        </h2>
        {caseList.map(item => (
          <div
            key={item.id}
            style={styles.card}
            onClick={() => navigate(`/home/case/${item.id}`)}
          >
            <img 
              src={item.image} 
              alt={`case ${item.id}`} 
              style={styles.image} 
              loading="lazy"  // 添加懒加载
            />
            <p style={styles.title}>{item.title}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

const styles = {
  sectionTitle: {
    textAlign: 'center',
    fontSize: '1.5em',
    marginBottom: '1.5em',
    color: '#00796b',  // 改为蓝色系
    fontWeight: '600'
  },
  container: {
    padding: '1.5em',
    fontFamily: 'Arial, sans-serif',
    maxWidth: '800px',
    margin: '0 auto',
  },
  card: {
    backgroundColor: '#fff',
    marginBottom: '1.5em',
    padding: '1.2em',
    borderRadius: '12px',
    display: 'flex',
    alignItems: 'center',
    gap: '1.5em',
    cursor: 'pointer',
    boxShadow: '0 3px 10px rgba(0,0,0,0.08)',
    transition: 'all 0.3s ease',
    ':hover': {
      transform: 'translateY(-3px)',
      boxShadow: '0 5px 15px rgba(0,0,0,0.1)'
    }
  },
  image: {
    width: '100px',
    height: '100px',
    borderRadius: '10px',
    objectFit: 'cover',
    border: '2px solid #b2ebf2'  // 添加蓝色边框
  },
  title: {
    flex: 1,
    fontWeight: '500',
    fontSize: '1.1em',
    color: '#333'
  },
};
